`ifdef SVT_PRE_VMM_12
class svt_spi_txrx_monitor_def_flash_cov_base;
`else
class svt_spi_txrx_monitor_def_flash_cov_base extends vmm_object;
`endif
`else
class svt_spi_txrx_monitor_def_flash_cov_base extends `SVT_XVM(object);
`endif

  /** svt_spi_transaction value, should be sampled when #xact_sample triggered. */
  protected svt_spi_transaction xact = null;
  protected svt_spi_agent_configuration cfg = null;
  // ****************************************************************************
  // Sampling Events
  // ****************************************************************************

  /** Event used to trigger transaction coverage. */  
  event xact_sample;

  // ****************************************************************************
  // Methods
  // ****************************************************************************
  
  //----------------------------------------------------------------------------
  /**
   * CONSTRUCTOR: Create a new svt_spi_txrx_monitor_def_flash_cov_base instance.
   */
  function new(string name = "",svt_spi_agent_configuration agent_cfg);
    this.cfg = agent_cfg;
  endfunction
  
  // -----------------------------------------------------------------------------
  virtual function void sample_status(svt_spi_transaction xact);
  endfunction
endclass
// =============================================================================

