  virtual function void sample_status(svt_spi_transaction xact);
    if ((cfg.spi_mem_cfg.catalog_part_number == "S25FL128S_HYBRID_EHPLC") || 
        (cfg.spi_mem_cfg.catalog_part_number == "S25FL128S_HYBRID_HPLC")) begin
