  virtual function void sample_status(svt_spi_transaction xact);
    if ((cfg.spi_mem_cfg.catalog_part_number == "S25FL256S_HYBRID_EHPLC") || 
        (cfg.spi_mem_cfg.catalog_part_number == "S25FL256S_HYBRID_HPLC")) begin
    // Set the data value.
    this.xact = xact;
    // Trigger the sampling
    -> this.xact_sample;
    end
  endfunction
